class Solution {
    public int minimizeXor(int num1, int num2) {
        int count = countSetBits(num2);
        int x = 0;
        for (int i = count; i >= 0; i--) {
            if (countBits(i) == i) {
                x |= i;
                num1 ^= i;
            }
        }
        return x;
    }

    private int countSetBits(int num) {
        int count = 0;
        while (num != 0) {
            count += num & 1;
            num >>= 1;
        }
        return count;
    }

    private int countBits(int num) {
        int count = 0;
        while (num != 0) {
            count++;
            num &= num - 1;
        }
        return count;
    }
}
